const body = $input.first().json.body || $input.first().json;
const raw = body.company || body.query || body.q || '';
const company = String(raw).trim().slice(0, 200);
if (!company || company.length < 2) {
  throw new Error('Missing or invalid "company" field. Send POST with JSON body: { "company": "SAP" }');
}
return [{ json: { company } }];

// Clearbit autocomplete: best for domain + logo. Free, CORS-enabled, ~1M companies.
const company = $('Validate Input').first().json.company;
const ERP_HINT = /erp|campus|edtech|lms|sms\b|school|college|student|academic|university/i;

let data = null;
try {
  const fetchCb = async (q) => {
    try {
      return await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://autocomplete.clearbit.com/v1/companies/suggest',
        qs: { query: q },
        json: true,
        timeout: 5000
      });
    } catch { return []; }
  };

  let suggestions = await fetchCb(company);
  const hasErpHit = (s) => ERP_HINT.test(s.domain || '') || ERP_HINT.test(s.name || '');
  if (Array.isArray(suggestions) && suggestions.length && !suggestions.some(hasErpHit)) {
    const erpSugs = await fetchCb(company + ' ERP');
    if (Array.isArray(erpSugs) && erpSugs.length) {
      const seen = new Set(suggestions.map(s => s.domain));
      suggestions = [...suggestions, ...erpSugs.filter(s => !seen.has(s.domain))];
    }
  }

  if (Array.isArray(suggestions) && suggestions.length) {
    const qNorm = company.toLowerCase().replace(/[^a-z0-9]/g, '');
    const score = (label) => {
      const t = (label || '').toLowerCase().replace(/[^a-z0-9]/g, '');
      if (t === qNorm) return 5;
      if (t === qNorm + 'erp' || t === qNorm + 'software' || t === qNorm + 'solutions') return 4;
      if (t.startsWith(qNorm) && t.length - qNorm.length <= 3) return 3;
      if (t.startsWith(qNorm)) return 2;
      const words = company.toLowerCase().split(/\s+/).filter(w => w.length > 2);
      if (words.length && words.every(w => t.includes(w))) return 1;
      return 0;
    };
    const ranked = suggestions
      .map(s => ({ ...s, score: score(s.name || ''), erpHint: hasErpHit(s) }))
      .filter(s => s.score > 0)
      .sort((a, b) => b.score - a.score || (b.erpHint ? 1 : 0) - (a.erpHint ? 1 : 0));
    if (ranked.length) {
      const topScore = ranked[0].score;
      const topTier = ranked.filter(s => s.score === topScore);
      const best = topTier.find(s => s.erpHint)
                || topTier.find(s => (s.domain || '').replace(/[^a-z0-9]/g, '').includes(qNorm))
                || topTier[0];
      if (best && best.domain) {
        data = {
          name: best.name,
          domain: best.domain,
          website: 'https://' + best.domain,
          logo: 'https://logo.clearbit.com/' + best.domain
        };
      }
    }
  }
} catch (err) { /* swallow — return null */ }

return [{ json: { source: 'clearbit', data } }];

// Wikidata: authoritative structured facts for companies with Wikipedia presence.
const company = $('Validate Input').first().json.company;
const COMPANY_RE = /\b(company|corporation|inc\b|ltd\b|llc\b|multinational|vendor|manufacturer|conglomerate|provider|software|enterprise|platform|system|erp)\b/i;
const norm = (s) => (s || '').toLowerCase().replace(/[^a-z0-9]/g, '');
const labelMatches = (label, q) => {
  const t = norm(label), s = norm(q);
  if (!t || !s) return false;
  if (t === s || t.startsWith(s) || s.startsWith(t)) return true;
  const words = q.toLowerCase().split(/\s+/).filter(w => w.length > 2);
  return words.length > 0 && words.every(w => t.includes(w));
};
const trimDesc = (text, max = 400) => {
  if (!text || text.length <= max) return text || null;
  const cut = text.lastIndexOf('. ', max);
  return cut > 60 ? text.slice(0, cut + 1) : text.slice(0, max - 1) + '\u2026';
};

let data = null;
try {
  const search = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.wikidata.org/w/api.php',
    qs: {
      action: 'wbsearchentities',
      search: company,
      type: 'item',
      language: 'en',
      limit: '10',
      format: 'json'
    },
    json: true,
    timeout: 8000
  }).catch(() => null);

  const hit = (search && Array.isArray(search.search) ? search.search : []).find(r =>
    labelMatches(r.label || '', company) && COMPANY_RE.test(r.description || '')
  );

  if (hit) {
    const entityRes = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.wikidata.org/w/api.php',
      qs: {
        action: 'wbgetentities',
        ids: hit.id,
        props: 'labels|descriptions|claims|sitelinks',
        sitefilter: 'enwiki',
        languages: 'en',
        format: 'json'
      },
      json: true,
      timeout: 8000
    }).catch(() => null);

    const entity = entityRes && entityRes.entities && entityRes.entities[hit.id];
    if (entity) {
      const claimVal = (prop) => {
        const c = entity.claims && entity.claims[prop];
        const snak = c && c[0] && c[0].mainsnak;
        if (!snak || snak.snaktype !== 'value') return null;
        const dv = snak.datavalue || {};
        const t = dv.type, v = dv.value;
        if (t === 'string')   return v;
        if (t === 'time')     return v && v.time ? v.time.slice(1, 5) : null;
        if (t === 'quantity') return v && v.amount ? String(v.amount).replace(/^\+/, '') : null;
        return null;
      };
      const website   = claimVal('P856');
      const founded   = claimVal('P571');
      const employees = claimVal('P1128');
      const hqId       = (entity.claims && entity.claims.P159 && entity.claims.P159[0] && entity.claims.P159[0].mainsnak && entity.claims.P159[0].mainsnak.datavalue && entity.claims.P159[0].mainsnak.datavalue.value && entity.claims.P159[0].mainsnak.datavalue.value.id) || null;
      const industryId = (entity.claims && entity.claims.P452 && entity.claims.P452[0] && entity.claims.P452[0].mainsnak && entity.claims.P452[0].mainsnak.datavalue && entity.claims.P452[0].mainsnak.datavalue.value && entity.claims.P452[0].mainsnak.datavalue.value.id) || null;

      let domain = null;
      try { if (website) domain = new URL(website).hostname.replace(/^www\./, ''); } catch {}

      const wikiTitle = (entity.sitelinks && entity.sitelinks.enwiki && entity.sitelinks.enwiki.title) || null;
      const idsToResolve = [hqId, industryId].filter(Boolean);

      const [wiki, labelRes] = await Promise.all([
        wikiTitle ? this.helpers.httpRequest({
          method: 'GET',
          url: 'https://en.wikipedia.org/api/rest_v1/page/summary/' + encodeURIComponent(wikiTitle),
          json: true,
          timeout: 8000
        }).catch(() => null) : Promise.resolve(null),
        idsToResolve.length ? this.helpers.httpRequest({
          method: 'GET',
          url: 'https://www.wikidata.org/w/api.php',
          qs: {
            action: 'wbgetentities',
            ids: idsToResolve.join('|'),
            props: 'labels',
            languages: 'en',
            format: 'json'
          },
          json: true,
          timeout: 8000
        }).catch(() => null) : Promise.resolve(null)
      ]);

      const hq       = hqId       ? ((labelRes && labelRes.entities && labelRes.entities[hqId] && labelRes.entities[hqId].labels && labelRes.entities[hqId].labels.en && labelRes.entities[hqId].labels.en.value) || null) : null;
      const industry = industryId ? ((labelRes && labelRes.entities && labelRes.entities[industryId] && labelRes.entities[industryId].labels && labelRes.entities[industryId].labels.en && labelRes.entities[industryId].labels.en.value) || null) : (hit.description || null);

      data = {
        name: (entity.labels && entity.labels.en && entity.labels.en.value) || hit.label,
        desc: trimDesc((wiki && wiki.extract) || null),
        website,
        domain,
        founded,
        hq,
        employees,
        industry
      };
    }
  }
} catch (err) { /* swallow — return null */ }

return [{ json: { source: 'wikidata', data } }];

// Consolidate prior lookups into one item that the Gemini chain consumes.
const company = $('Validate Input').first().json.company;
const cb = ($('Clearbit Lookup').first() && $('Clearbit Lookup').first().json && $('Clearbit Lookup').first().json.data) || null;
const wd = ($('Wikidata Lookup').first() && $('Wikidata Lookup').first().json && $('Wikidata Lookup').first().json.data) || null;

return [{
  json: {
    company,
    knownName:      (wd && wd.name) || (cb && cb.name) || null,
    knownDomain:    (cb && cb.domain) || (wd && wd.domain) || null,
    knownDesc:      (wd && wd.desc) || null,
    knownHq:        (wd && wd.hq) || null,
    knownFounded:   (wd && wd.founded) || null,
    knownEmployees: (wd && wd.employees) || null,
    knownIndustry:  (wd && wd.industry) || null,
    knownWebsite:   (wd && wd.website) || (cb && cb.website) || null
  }
}];

parameters.text:
=Research this company: {{ $json.company }}

VERIFIED FACTS already gathered (treat as ground truth — do NOT contradict these unless you have stronger evidence):
- Canonical name: {{ $json.knownName || 'unknown' }}
- Domain: {{ $json.knownDomain || 'unknown' }}
- Description: {{ $json.knownDesc || 'unknown' }}
- HQ: {{ $json.knownHq || 'unknown' }}
- Founded: {{ $json.knownFounded || 'unknown' }}
- Employees: {{ $json.knownEmployees || 'unknown' }}
- Industry: {{ $json.knownIndustry || 'unknown' }}

Your task:
1. Fill in fields where the verified data is unknown.
2. PRIORITIZE: revenue, erp, tags, desc.
3. For any field where you cannot achieve high confidence, return null. Do NOT guess.
4. Echo verified facts back into the corresponding fields when known (e.g. set hq from the verified value).

Return the JSON object now.

