{
  "type": "object",
  "properties": {
    "name":      { "type": ["string", "null"], "description": "Canonical company name" },
    "desc":      { "type": ["string", "null"], "description": "2-3 factual sentences, no marketing language" },
    "industry":  { "type": ["string", "null"], "description": "Primary industry classification" },
    "hq":        { "type": ["string", "null"], "description": "Headquarters as 'City, Country'" },
    "employees": { "type": ["string", "null"], "description": "Numeric string e.g. '23000'" },
    "founded":   { "type": ["string", "null"], "description": "4-digit founding year" },
    "revenue":   { "type": ["string", "null"], "description": "e.g. '$32.7 billion (FY2024)'" },
    "erp":       { "type": ["string", "null"], "description": "Specific ERP product name if applicable" },
    "tags":      { "type": ["array", "null"], "items": { "type": "string" }, "description": "2-4 short classification labels" }
  },
  "required": ["name", "desc", "industry", "hq", "employees", "founded", "revenue", "erp", "tags"],
  "additionalProperties": false
}

parameters.jsCode:
// Field-level priority merge.
// Priority per field: Wikidata (authoritative) > Clearbit > Gemini > pattern-inference.
// Logo always Clearbit (most reliable). Revenue/erp/tags only Gemini (others don't provide).

const cb = ($('Clearbit Lookup').first() && $('Clearbit Lookup').first().json && $('Clearbit Lookup').first().json.data) || null;
const wd = ($('Wikidata Lookup').first() && $('Wikidata Lookup').first().json && $('Wikidata Lookup').first().json.data) || null;

let gem = null;
try {
  const raw = $input.first().json;
  // Basic LLM Chain with structured parser usually outputs the parsed object directly,
  // but the wrapper key varies (output / text). Handle both.
  let out = (raw && raw.output !== undefined) ? raw.output : raw;
  if (typeof out === 'string') out = JSON.parse(out);
  gem = (out && typeof out === 'object') ? out : null;
} catch { gem = null; }

const pick = (...vals) => {
  for (const v of vals) {
    if (v !== null && v !== undefined && v !== '') return v;
  }
  return null;
};

// Pattern-inference fallback for ERP type when Gemini returns null.
const inferErp = (name, desc) => {
  const text = ((name || '') + ' ' + (desc || '')).toLowerCase();
  if (/educational?\s*erp|campus\s*(erp|management|solution)|student\s*(information|management)\s*system|school\s*(erp|management)|university\s*erp|college\s*erp/i.test(text)) return 'Educational ERP';
  if (/\berp\b|enterprise\s*resource\s*plan/i.test(text)) return 'ERP';
  return null;
};

const name = pick(wd && wd.name, cb && cb.name, gem && gem.name);
const desc = pick(wd && wd.desc, gem && gem.desc);

const merged = {
  name,
  desc,
  industry:     pick(wd && wd.industry, gem && gem.industry),
  hq:           pick(wd && wd.hq, gem && gem.hq),
  employees:    pick(wd && wd.employees, gem && gem.employees),
  founded:      pick(wd && wd.founded, gem && gem.founded),
  revenue:      pick(gem && gem.revenue),
  erp:          pick(gem && gem.erp, inferErp(name, desc)),
  tags:         (gem && Array.isArray(gem.tags) && gem.tags.length) ? gem.tags.slice(0, 4) : null,
  website:      pick(wd && wd.website, cb && cb.website),
  domain:       pick(cb && cb.domain, wd && wd.domain),
  logo:         pick(cb && cb.logo),
  logoFallback: null,
  sources: {
    clearbit: cb !== null,
    wikidata: wd !== null,
    gemini:   gem !== null
  }
};

return [{ json: merged }];
